import{c as a,Q as n,j as i,m as t}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"调度器","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/16-调度器.md","filePath":"osLearning/16-调度器.md","lastUpdated":1781095972000}'),e={name:"osLearning/16-调度器.md"};function p(l,s,h,o,r,d){return n(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="调度器" tabindex="-1">调度器 <a class="header-anchor" href="#调度器" aria-label="Permalink to &quot;调度器&quot;">​</a></h1><p>有个真实到不能再真实的事故剧本:服务压测吞吐上不去,有人拍板&quot;线程池从 200 加到 400&quot;,重新压——<strong>吞吐反而降 15%,p99 翻倍</strong>,会议室一片安静。根源是一个普遍误解:<strong>以为线程是&quot;雇一个人干一份活&quot;,人越多活干得越快</strong>。实际上 CPU 核数是死的,线程只是&quot;想上 CPU 的排队者&quot;,超过核数的部分全在队里站着——而排队、换人、搬家,每一步都有调度器在背后记账收费。这一篇讲清楚:CFS 怎么决定下一个谁跑、nice 值到底改了什么、上下文切换的钱花在哪、实时调度为什么能把整台机器&quot;饿死&quot;、线程数到底怎么定。</p><blockquote><p>一句话先记住:<strong>调度器是 CPU 时间的仲裁者,Linux CFS 的仲裁原则是&quot;谁拿到的 CPU 最少,谁下一个跑&quot;</strong>。可运行线程数一旦超过核数,多出来的全在 run queue 排队,延迟直接涨。<strong>CPU 密集型线程数 ≈ 核数,IO 密集型按等待比例放大</strong>。实时调度能插队,但用错一行代码就能让 ssh 都连不上。</p></blockquote><hr><h2 id="一、调度器在仲裁什么" tabindex="-1">一、调度器在仲裁什么 <a class="header-anchor" href="#一、调度器在仲裁什么" aria-label="Permalink to &quot;一、调度器在仲裁什么&quot;">​</a></h2><p>一台 8 核机器上,随手 <code>ps -eLf | wc -l</code> 能数出上千个线程:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU:   8 个硬件执行位</span></span>
<span class="line"><span>线程:  1000+ 个&quot;想跑&quot;的执行流</span></span>
<span class="line"><span>问题:  谁先跑?跑多久?被谁打断?在哪个核上跑?</span></span></code></pre></div><p>调度器要同时伺候五个互相打架的目标:</p><ul><li><strong>公平</strong>:不能让任何进程永远轮不上;</li><li><strong>吞吐</strong>:CPU 别空转,切换别太频繁(切换本身不产出);</li><li><strong>延迟</strong>:你敲键盘的进程要立刻响应,哪怕后台在跑编译;</li><li><strong>亲和性</strong>:线程尽量留在原来的核上——换核等于 L1/L2 cache 全部白热(详见 10 篇);</li><li><strong>优先级</strong>:重要的多吃,不重要的让着点。</li></ul><p>注意吞吐和延迟天然矛盾:<strong>切换越少吞吐越高,切换越勤响应越快</strong>。调度器的所有设计,都是在这根钢丝上找平衡。</p><hr><h2 id="二、谁有资格排队-任务状态与-run-queue" tabindex="-1">二、谁有资格排队:任务状态与 run queue <a class="header-anchor" href="#二、谁有资格排队-任务状态与-run-queue" aria-label="Permalink to &quot;二、谁有资格排队:任务状态与 run queue&quot;">​</a></h2><p>调度器不是在&quot;所有线程&quot;里挑——绝大多数线程根本不想跑,它们在睡觉等事件。Linux 的任务状态(详见 11 篇):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TASK_RUNNING          可运行/正在运行     ← 只有它在抢 CPU</span></span>
<span class="line"><span>TASK_INTERRUPTIBLE    可中断睡眠(等 IO、等锁,ps 里的 S)</span></span>
<span class="line"><span>TASK_UNINTERRUPTIBLE  不可中断睡眠(ps 里的 D,通常卡在磁盘/NFS)</span></span>
<span class="line"><span>TASK_STOPPED          被暂停(Ctrl-Z / SIGSTOP)</span></span>
<span class="line"><span>TASK_ZOMBIE           僵尸,等父进程收尸</span></span></code></pre></div><p><strong>真正参与排队的只有 TASK_RUNNING</strong>。&quot;机器上有 1000 个线程&quot;不可怕,可怕的是&quot;100 个 runnable 挤 8 个核&quot;——<code>uptime</code> 的 load average 量的就是这个(加上 D 状态)。</p><p>每个 CPU 有<strong>自己私有的 run queue</strong>,不是全局一条队(全局队会让所有核抢同一把锁,详见 14 篇):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU0 rq: T1 T3 T8     ← 各排各的队</span></span>
<span class="line"><span>CPU1 rq: T2 T4</span></span>
<span class="line"><span>CPU2 rq: T5</span></span>
<span class="line"><span>CPU3 rq: (空闲)</span></span></code></pre></div><p>队伍长短不齐时,<strong>负载均衡器</strong>周期性把任务从忙核搬到闲核。但搬家不免费:任务的热数据还留在原来核的 cache 里,搬过去等于带着空 cache 重新开张。<strong>调度器在&quot;均衡&quot;和&quot;亲和&quot;之间永远只能取折中</strong>。</p><hr><h2 id="三、cfs-用一棵红黑树实现-完全公平" tabindex="-1">三、CFS:用一棵红黑树实现&quot;完全公平&quot; <a class="header-anchor" href="#三、cfs-用一棵红黑树实现-完全公平" aria-label="Permalink to &quot;三、CFS:用一棵红黑树实现&quot;完全公平&quot;&quot;">​</a></h2><p>Linux 默认调度器叫 <strong>CFS(Completely Fair Scheduler,完全公平调度器)</strong>,设计思想出奇纯粹:不发固定时间片,只维护一个数字——</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vruntime(虚拟运行时间)= 任务实际跑掉的 CPU 时间 × 权重修正</span></span></code></pre></div><p><strong>仲裁规则就一条:谁的 vruntime 最小,说明谁&quot;吃得最少、亏得最大&quot;,下一个就让谁跑</strong>。跑的时候 vruntime 持续增长,涨到不再是最小,就换下一个。所有任务的 vruntime 像被一根橡皮筋拴着,谁也甩不开谁——这就是&quot;完全公平&quot;。</p><h3 id="_3-1-红黑树-o-log-n-找到最亏的人" tabindex="-1">3.1 红黑树:O(log n) 找到最亏的人 <a class="header-anchor" href="#_3-1-红黑树-o-log-n-找到最亏的人" aria-label="Permalink to &quot;3.1 红黑树:O(log n) 找到最亏的人&quot;">​</a></h3><p>可运行任务按 vruntime 组织成一棵红黑树:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ( vruntime=205 )</span></span>
<span class="line"><span>                   /               \\</span></span>
<span class="line"><span>          ( 102 )                   ( 310 )</span></span>
<span class="line"><span>         /       \\                 /</span></span>
<span class="line"><span>   ( 87 )       ( 150 )      ( 260 )</span></span>
<span class="line"><span>   /</span></span>
<span class="line"><span>( 41 ) ← 最左节点 = vruntime 最小 = 下一个上 CPU 的</span></span>
<span class="line"><span>─────────────────────────────────────────────</span></span>
<span class="line"><span>  挑任务:    摘最左节点(有缓存指针,实际 O(1))</span></span>
<span class="line"><span>  任务下场:  按新 vruntime 插回树里,O(log n)</span></span>
<span class="line"><span>  睡醒的任务: vruntime 补到接近当前最小值再入树</span></span>
<span class="line"><span>             (不让它&quot;睡一觉血亏&quot;,也不让它&quot;睡出特权&quot;)</span></span></code></pre></div><p>优雅之处在于:<strong>没有时间片轮转表,公平性是数据结构自动涌现的</strong>——交互式任务大部分时间在睡(vruntime 涨得慢),一醒来就是树上最左,天然低延迟;批处理任务一直跑(vruntime 涨得快),自动往树右边沉,天然让路。</p><h3 id="_3-2-nice-改的是涨价速度-不是配额" tabindex="-1">3.2 nice:改的是涨价速度,不是配额 <a class="header-anchor" href="#_3-2-nice-改的是涨价速度-不是配额" aria-label="Permalink to &quot;3.2 nice:改的是涨价速度,不是配额&quot;">​</a></h3><p><code>nice</code> 值范围 -20 到 19,越小越&quot;凶&quot;:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nice</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./batch-job</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 启动时降权</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">renice</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 12345</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 给运行中进程提权(负值需要 root)</span></span></code></pre></div><p>nice 通过<strong>权重</strong>起作用:nice 低 → 权重大 → 同样跑 10ms,<strong>vruntime 涨得慢</strong> → 更久霸住&quot;树最左&quot; → 实际分到更多 CPU。相邻 nice 值权重差约 1.25 倍。</p><p>最要紧的纠偏:<strong>nice 不是&quot;固定分配百分之多少 CPU&quot;</strong>,它只改<strong>有竞争时</strong>的相对份额——机器空闲时,nice 19 的任务照样吃满整个核。</p><hr><h2 id="四、上下文切换-每一次都在交-cache-税" tabindex="-1">四、上下文切换:每一次都在交&quot;cache 税&quot; <a class="header-anchor" href="#四、上下文切换-每一次都在交-cache-税" aria-label="Permalink to &quot;四、上下文切换:每一次都在交&quot;cache 税&quot;&quot;">​</a></h2><p>上下文切换(context switch)的账单分两部分。</p><p><strong>直接成本</strong>(切换动作本身):保存当前任务的寄存器、栈指针、程序计数器;切换内核栈;进程间切换还要换地址空间(页表基址),<strong>TLB 大面积失效</strong>(详见 06 篇);再恢复下一个任务的上下文。</p><p><strong>间接成本</strong>(往往更贵):新任务把 L1/L2 cache 一点点填成自己的数据,<strong>前一个任务切回来时热数据全凉了</strong>,每次访存重新走慢路径。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>直接成本:    一次切换 几百 ns ~ 几 μs</span></span>
<span class="line"><span>间接成本:    cache 重新热起来,可能拖慢之后几十 μs 的执行</span></span>
<span class="line"><span>线程 vs 进程: 同进程线程切换便宜些(不换地址空间、TLB 保得住),</span></span>
<span class="line"><span>              但 cache 污染一分不少</span></span></code></pre></div><p>每秒几万次切换时,这笔税从&quot;噪声&quot;变成&quot;主要支出&quot;——<strong>这正是开头&quot;线程翻倍吞吐反降&quot;的账本</strong>:200 线程时排队不长切换不频;400 线程后 runnable 远超核数,CPU 时间的相当一部分花在换人和重热 cache 上,真正干活的比例反而降了。</p><h3 id="_4-1-怎么观察" tabindex="-1">4.1 怎么观察 <a class="header-anchor" href="#_4-1-怎么观察" aria-label="Permalink to &quot;4.1 怎么观察&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vmstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # cs 列:全机每秒上下文切换次数</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pidstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 每进程:cswch(主动让出)/ nvcswch(被抢占)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">perf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sched</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> record</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">perf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sched</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> latency</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 每个任务等了多久才上 CPU ← 排查 p99 的利器</span></span></code></pre></div><p><code>pidstat -w</code> 两列分开读:<strong>cswch 高 = 任务自己频繁阻塞</strong>(锁、小 IO、sleep);<strong>nvcswch 高 = 想跑总被抢</strong>(runnable 太多)。cs 高得离谱的常见嫌疑人:线程太多、锁竞争激烈(详见 14 篇,等锁=睡眠=切换)、小 IO 太碎、频繁 sleep/wakeup、线程池队列设计差。</p><hr><h2 id="五、抢占-你随时可能被请下场" tabindex="-1">五、抢占:你随时可能被请下场 <a class="header-anchor" href="#五、抢占-你随时可能被请下场" aria-label="Permalink to &quot;五、抢占:你随时可能被请下场&quot;">​</a></h2><p>调度不只在任务&quot;自愿让位&quot;时发生。完整的调度时机:</p><ul><li>任务主动阻塞:读 IO、等锁、sleep;</li><li>时间片用完(CFS 里是&quot;你的 vruntime 不再最小&quot;);</li><li>更高优先级 / 更小 vruntime 的任务被唤醒;</li><li>中断返回用户态前,检查 <code>need_resched</code> 标志;</li><li>系统调用返回前,同样检查。</li></ul><p>这就是<strong>抢占式调度(preemptive scheduling)</strong>:好处是死循环程序霸占不了机器;代价是<strong>你的代码可能在任何两条指令之间被切走</strong>。所以&quot;这两行挨得很近,不会被打断吧&quot;是并发编程里最危险的侥幸——不会被打断的代码不存在,只有被锁保护的代码(14 篇)。</p><hr><h2 id="六、实时调度-能插队的贵宾-也能饿死全场" tabindex="-1">六、实时调度:能插队的贵宾,也能饿死全场 <a class="header-anchor" href="#六、实时调度-能插队的贵宾-也能饿死全场" aria-label="Permalink to &quot;六、实时调度:能插队的贵宾,也能饿死全场&quot;">​</a></h2><p>CFS 只是&quot;普通舱&quot;。完整菜单:</p><table tabindex="0"><thead><tr><th>策略</th><th>一句话</th></tr></thead><tbody><tr><td><code>SCHED_OTHER</code></td><td>普通 CFS,默认</td></tr><tr><td><code>SCHED_BATCH</code></td><td>批处理:&quot;我不在乎延迟&quot;,少打扰交互任务</td></tr><tr><td><code>SCHED_IDLE</code></td><td>极低优先级,所有人都不跑了才轮到</td></tr><tr><td><code>SCHED_FIFO</code></td><td>实时:先到先跑,<strong>不阻塞、不被更高优先级抢,就一直跑</strong></td></tr><tr><td><code>SCHED_RR</code></td><td>实时:同优先级轮转,其余同 FIFO</td></tr><tr><td><code>SCHED_DEADLINE</code></td><td>按&quot;运行时长/周期/截止期&quot;调度,最硬核</td></tr></tbody></table><p>关键规则:<strong>任何实时任务的优先级都高于全部普通任务</strong>。CFS 的 vruntime 公平在实时任务面前一文不值。于是有了名场面——某团队给&quot;延迟敏感&quot;线程上了 <code>SCHED_FIFO</code>,代码里恰好有段忙等:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实时线程: while (!flag) {}     ← 忙等,永不阻塞,FIFO 永不下场</span></span>
<span class="line"><span>后果:     这个核上的所有普通任务 0 CPU</span></span>
<span class="line"><span>          核上跑着 sshd     → ssh 连不上</span></span>
<span class="line"><span>          跑着监控 agent    → 报警系统先瞎</span></span>
<span class="line"><span>          跑着 kworker      → 内核自己的活都干不了</span></span>
<span class="line"><span>现象:     机器&quot;卡死&quot;,但 ping 得通 ← 中断还活着,只是没人调度用户进程</span></span></code></pre></div><p>听起来吓人,其实内核留了最后一道保险:默认 <code>sched_rt_runtime_us / sched_rt_period_us = 950000/1000000</code>,<strong>实时任务每秒最多吃 95%,强制留 5% 给普通任务喘气</strong>——事故现场你还能登上去,多半靠的就是这 5%。但别赌它:<strong>除非是音视频、机器人、交易撮合、工业控制这类真硬实时场景,且每条实时路径保证会阻塞,否则别碰 SCHED_FIFO/RR</strong>。实时 + 锁还必须开优先级继承,不然就是 14 篇的火星探路者事故。</p><hr><h2 id="七、绑核与-numa-位置也是性能" tabindex="-1">七、绑核与 NUMA:位置也是性能 <a class="header-anchor" href="#七、绑核与-numa-位置也是性能" aria-label="Permalink to &quot;七、绑核与 NUMA:位置也是性能&quot;">​</a></h2><h3 id="_7-1-cpu-亲和性" tabindex="-1">7.1 CPU 亲和性 <a class="header-anchor" href="#_7-1-cpu-亲和性" aria-label="Permalink to &quot;7.1 CPU 亲和性&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">taskset</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0-3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./server</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 启动时绑定到核 0-3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">taskset</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 12345</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 把运行中的进程绑到核 2</span></span></code></pre></div><p>绑核(CPU affinity)的正当理由都围绕一件事——<strong>保住 cache 热度和确定性</strong>:延迟敏感线程独占核、网卡中断固定到专门的核、NUMA 场景把计算钉在内存旁边。不正当理由也常见:不了解负载就乱绑,几个核过载其余闲死——<strong>负载均衡是你拿不准时的更优解,绑核是你非常确定时的精调</strong>。容器里还要叠一层小心:cgroup 的 cpuset/quota 已经在限制 CPU,再手工绑核,两层规则打架,行为更难预测。</p><h3 id="_7-2-numa-内存有远近" tabindex="-1">7.2 NUMA:内存有远近 <a class="header-anchor" href="#_7-2-numa-内存有远近" aria-label="Permalink to &quot;7.2 NUMA:内存有远近&quot;">​</a></h3><p>多路服务器上&quot;内存&quot;不是均匀的池子:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─ Socket 0 ──────┐          ┌─ Socket 1 ──────┐</span></span>
<span class="line"><span>│ CPU 0-15        │  互联总线 │ CPU 16-31       │</span></span>
<span class="line"><span>│   │ 本地访问,快 │◄────────►│   │ 本地访问,快 │</span></span>
<span class="line"><span>│ 内存节点 0      │   跨节点  │ 内存节点 1      │</span></span>
<span class="line"><span>└─────────────────┘ 慢1.3-2倍 └─────────────────┘</span></span></code></pre></div><p>调度器和内存分配器会尽量维持&quot;线程在哪个 node 跑,内存就从哪个 node 分&quot;。但线程被搬几次家后,容易落到&quot;CPU 在 node0、内存在 node1&quot;的别扭姿势——每次访存付 1.3-2 倍的跨节点税。排查与固定:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">numactl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hardware</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                            # 看拓扑</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">numastat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                             # 这个进程的内存落在哪个 node</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">numactl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cpunodebind=0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --membind=0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./server</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # CPU 和内存一起钉死在 node0</span></span></code></pre></div><hr><h2 id="八、线程数到底怎么定" tabindex="-1">八、线程数到底怎么定 <a class="header-anchor" href="#八、线程数到底怎么定" aria-label="Permalink to &quot;八、线程数到底怎么定&quot;">​</a></h2><p>回到开头的事故。线程数的算法取决于线程在干嘛:</p><p><strong>CPU 密集型</strong>(编码、压缩、计算):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>线程数 ≈ CPU 核数</span></span></code></pre></div><p>每个线程都能吃满一个核,多开的部分纯粹在排队 + 制造切换,<strong>只亏不赚</strong>。</p><p><strong>IO 密集型</strong>(等 DB、等下游):线程大部分时间在睡,睡着的不占 CPU,可以多开:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>线程数 ≈ 核数 × (1 + 等待时间 / 计算时间)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例:一次请求计算 5ms + 等 DB 45ms</span></span>
<span class="line"><span>    → 核数 × (1 + 45/5) = 核数 × 10</span></span>
<span class="line"><span>    8 核 ≈ 80 线程,刚好让 CPU 在大家轮流睡觉时不空转</span></span></code></pre></div><p>但这个公式算的是<strong>上限</strong>,不是答案。真实世界还有四道闸门:DB 连接池(80 个线程抢 20 个连接,多出的 60 个在等池子不是等 CPU)、下游限流、每线程的栈内存、锁竞争(线程越多,14 篇的 futex 排队越长)。<strong>正确做法:公式定起点,压测看 p99 和 cs,逐步逼近</strong>——而不是&quot;不够就翻倍&quot;。</p><p>顺着公式也能看到天花板:等待/计算比 100:1 的场景(海量长连接),线程数要上万,内存和切换成本先崩——<strong>这正是协程登场的理由,下一篇的主题</strong>。</p><hr><h2 id="九、三个高频故障现场" tabindex="-1">九、三个高频故障现场 <a class="header-anchor" href="#九、三个高频故障现场" aria-label="Permalink to &quot;九、三个高频故障现场&quot;">​</a></h2><h3 id="_9-1-cpu-100-吞吐却不涨" tabindex="-1">9.1 CPU 100%,吞吐却不涨 <a class="header-anchor" href="#_9-1-cpu-100-吞吐却不涨" aria-label="Permalink to &quot;9.1 CPU 100%,吞吐却不涨&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uptime</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # load 远超核数 → runnable 排长队</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">top</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -H</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">pi</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 按线程看:谁在烧 CPU</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pidstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 切换次数 + CPU 占用一起看</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">perf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> top</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 烧在哪个函数:业务?自旋锁?GC?memcpy?</span></span></code></pre></div><p>常见病根:runnable 太多(回看第八节)、锁竞争退化成自旋空转、GC 线程抢 CPU、切换吃掉真实算力、<strong>容器 CPU quota 被打满</strong>(看下面)。</p><h3 id="_9-2-p99-偶发抖动" tabindex="-1">9.2 p99 偶发抖动 <a class="header-anchor" href="#_9-2-p99-偶发抖动" aria-label="Permalink to &quot;9.2 p99 偶发抖动&quot;">​</a></h3><p>平均延迟很好,p99 偶尔飙——典型&quot;调度税&quot;症状:线程 ready 了却在 run queue 等几毫秒、跨核迁移后 cache 全凉、CPU 动态降频、网卡中断打在业务核上、<strong>cgroup CPU throttle</strong>(容器配 0.5 核,burst 一下就被掐到下个周期)。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/cgroup/cpu.stat</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # nr_throttled / throttled_usec:被掐了多少次</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">perf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sched</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> latency</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 调度等待,直接量化&quot;排队税&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/interrupts</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 中断都打在哪个核</span></span></code></pre></div><p>容器里 <code>nr_throttled</code> 持续涨,就别再看代码了——<strong>是配额问题,不是程序问题</strong>。</p><h3 id="_9-3-一堆-d-状态" tabindex="-1">9.3 一堆 D 状态 <a class="header-anchor" href="#_9-3-一堆-d-状态" aria-label="Permalink to &quot;9.3 一堆 D 状态&quot;">​</a></h3><p><code>D</code>(不可中断睡眠)= 卡在磁盘/NFS/块设备 IO,<strong>kill -9 都杀不动</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -eo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pid,stat,wchan,cmd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;$2 ~ /D/&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # wchan 列:卡在内核哪个函数</span></span></code></pre></div><p>大量 D 状态时调度器是被冤枉的——它也想调度这些任务,但它们在等存储。根因去查磁盘、NFS、块设备队列,而不是调 nice。</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><ol><li><strong>以为线程越多越快</strong>——runnable 超过核数就是纯排队,翻倍线程换来吞吐下降是经典名场面</li><li><strong>以为 nice 是&quot;分配百分比&quot;</strong>——它只改竞争时的相对权重,机器空闲时 nice 19 照样吃满核</li><li><strong>给忙等代码上 SCHED_FIFO</strong>——实时任务不下场,普通任务全饿死,只剩内核留的 5% 保命</li><li><strong>实时线程用普通 mutex 不开优先级继承</strong>——优先级反转,重演火星探路者(详见 14 篇)</li><li><strong>假设&quot;代码很短不会被切走&quot;</strong>——抢占发生在任何两条指令之间,只有锁能保护你</li><li><strong>不了解负载就乱绑核</strong>——几个核过载其余闲死,负载均衡本来做得比你好</li><li><strong>容器里 CPU 慢先怪代码</strong>——先看 cpu.stat 的 throttle 计数,经常是 quota 配小了</li><li><strong>把 load average 当 CPU 使用率</strong>——load 算 runnable + D 状态,大量 D 时 load 高但 CPU 很闲,根因在存储</li><li><strong>cs 高只会加机器</strong>——先分清主动切换(锁/IO 碎)还是被动切换(线程太多),加机器治不了配置错</li><li><strong>跨 NUMA 不闻不问</strong>——CPU 和内存分居两个 node,每次访存交 1.3-2 倍的税,numastat 一看便知</li></ol><hr><p>下一篇:<code>17-协程.md</code>,讲调度的&quot;用户态续集&quot;——当并发量到了&quot;线程数 × 栈内存&quot;和&quot;切换税&quot;都扛不住的量级,<strong>把调度从内核搬到用户态</strong>就是唯一出路。Go 的 G-M-P、Python asyncio、Rust async 全是这个思路的不同流派;也回答那道白板名题:<strong>为什么 Go 协程这么轻量,但密集 CPU 任务用线程更快</strong>。</p>`,92)])])}const g=a(e,[["render",p]]);export{k as __pageData,g as default};
